GS.CommonMenu.gamesDropdownTemplate = function(data) {
    var p = [];
    with (data) {
        p.push('<div class="cm-showcase-nav">');
        p.push('<a href="#" class="cm-showcase-nav_link cm-showcase-nav_link__left js-carousel-left">');
        p.push('<span class="cm-showcase-nav_ico-wrapper"></span>');
        p.push('<span class="cm-showcase-nav_ico cm-showcase-nav_ico__left"></span>');
        p.push('</a>');
        p.push('<a href="#" class="cm-showcase-nav_link cm-showcase-nav_link__right js-carousel-right">');
        p.push('<span class="cm-showcase-nav_ico-wrapper"></span>');
        p.push('<span class="cm-showcase-nav_ico cm-showcase-nav_ico__right"></span>');
        p.push('</a>');
        p.push('</div>');
        p.push('<h1 class="cm-showcase_heading">', escape(_("text_showcase_title_games")), ':</h1>');
        p.push('<div class="cm-showcase_wrapper js-showcase-wrapper">');
        p.push('<ul class="cm-showcase_list js-tab-carousel">');

        forEach(config, function(game, index) {
            p.push('<li class="cm-showcase_item');
            if (game.color) {
                p.push(" cm-showcase_item__", escape(game.color), "");
            }
            p.push(' js-tab-carousel-element" data-tab-name="', escape(game.name), '">');
            p.push('<style>');
            p.push('#common_menu .cm-showcase_item__', escape(game.color), ' .cm-tab__opened,');
            p.push('#common_menu .cm-not-touch .cm-showcase_item__', escape(game.color), ' .cm-tab:hover {');
            p.push('color: #', escape(game.color), ';');
            p.push('}');
            p.push('#common_menu .cm-showcase_item__', escape(game.color), ' .cm-showcase-related_new-mark,');
            p.push('#common_menu .cm-showcase_item__', escape(game.color), ' .cm-showcase-related_title,');
            p.push('#common_menu .cm-showcase_item__', escape(game.color), ' .cm-showcase-about_title {');
            p.push('color: #', escape(game.color), ';');
            p.push('}');
            p.push('</style>');
            p.push('<span class="cm-tab js-cm-dropdown-link js-cm-sub-menu" data-tab-name="', escape(game.name), '" data-active-class="cm-tab__opened">');
            p.push('<span class="cm-tab_ico-wrapper">');
            p.push('<span class="cm-tab_ico-holder js-tab-mark ');
            if (isTabHighlighted(game, options)) {
                p.push("cm-tab_ico-holder__marked");
            }
            p.push('" data-active-class="cm-tab_ico-holder__marked">');
            if (game.icon_svg_body && allowSVG()) {
                p.push(" ", game.icon_svg_body, " ");
            } else {
                p.push(' <img class="cm-tab_ico" src="', escape(buildImageUrl(game.icon, options)), '" alt=""> ');
            }
            p.push(' </span>');
            p.push('</span>');
            p.push('<span class="cm-tab_text">', escape(_u(game.tab_name)), '</span>');
            p.push(' <span class="cm-arrow cm-arrow__mobile"></span>');
            p.push('</span>');
            p.push('<div class="cm-visual js-cm-dropdown" data-dropdown="sub-menu:games" data-active-class="cm-visual__opened">');
            p.push('<div class="cm-visual_bg">');
            p.push('<span class="cm-visual_image-wrapper">');
            p.push('<span class="cm-visual_image-holder">');
            p.push('<img class="cm-visual_image cm-visual_image__desktop js-image-lazy-load-desktop" data-src="', escape(buildImageUrl(game.desktop_keyart, options)), '" alt="">');
            p.push('<img class="cm-visual_image cm-visual_image__tablet js-image-lazy-load-tablet" data-src="', escape(buildImageUrl(game.tablet_keyart, options)), '" alt="">');
            p.push('<img class="cm-visual_image cm-visual_image__mobile js-image-lazy-load-mobile" data-src="', escape(buildImageUrl(game.mobile_keyart, options)), '" alt="">');
            p.push('</span>');
            p.push('</span>');
            p.push('</div>');
            p.push('<div class="cm-visual_content">');
            if (game.url) {
                p.push(' <a class="cm-visual_logo-wrapper" href="', escape(addUtm(game.url)), '">');
                p.push('<div class="cm-visual_logo-holder">');
                p.push('<img class="cm-visual_logo" src="', escape(buildImageUrl(game.logo, options)), '" alt="">');
                p.push('</div>');
                p.push('</a>');
            } else {
                p.push('<div class="cm-visual_logo-wrapper">');
                p.push('<div class="cm-visual_logo-holder">');
                p.push('<img class="cm-visual_logo" src="', escape(buildImageUrl(game.logo, options)), '" alt="">');
                p.push('</div>');
                p.push('</div>');
            }
            p.push('<div class="cm-visual_description">');
            p.push('<div class="cm-showcase-related">');
            p.push('<h2 class="cm-showcase-related_title">', escape(_("links_title_text")), '</h2>');
            p.push('<ul class="cm-showcase-related_list">');
            forEach(game.extra_links, function(link, linkIndex) {
                p.push(" ");
                var isHighlighted = isLinkHighlighted(link, options);
                p.push('<li class="cm-showcase-related_item">');
                p.push('<a class="cm-showcase-related_link ');
                if (isHighlighted) {
                    p.push("js-extra-link-new");
                }
                p.push('" data-extralink-hash="', escape(link.notifying_hash), '" href="', escape(addUtm(link.url)), '">');
                p.push('<span class="cm-showcase-related_text">', escape(_u(link.title_text)), "</span>");
                if (isHighlighted) {
                    p.push(' <span class="cm-showcase-related_new-mark js-extra-link-new-text">', escape(_("text_new")), "</span> ");
                }
                p.push("</a>");
                p.push("</li>");
            });
            p.push('</ul>');
            p.push('</div>');
            p.push('<div class="cm-showcase-about">');
            p.push('<h2 class="cm-showcase-about_title">', escape(_u(game.desc_title)), '</h2>');
            p.push('<div class="cm-showcase-about_holder">');
            p.push('<p class="cm-showcase-about_text">', escape(_u(game.desc_text)), '</p>');
            p.push('<div class="cm-platforms">');
            forEach(game.platforms, function(platform, platformKey) {
                p.push(' <span class="cm-platforms_item">');
                p.push('<span class="cm-platforms_icon cm-platforms_icon__', escape(platformKey), '">', escape(platform), '</span>');
                p.push(' <span class="cm-platforms_text">', escape(platform), "</span> ");
                p.push("</span>");
            });
            p.push('</div>');
            p.push('</div>');
            p.push('</div>');
            p.push('</div>');
            p.push('</div>');
            p.push('</div>');
            p.push('</li>');
        });

        p.push('</ul>');
        p.push('</div>');
        p.push('<div class="cm-up cm-up__bordered">');
        p.push('<a class="cm-up_link js-cm-up_link" href="#">');
        p.push('<span class="cm-up_arrow">arrow up</span>');
        p.push('</a>');
        p.push('</div>');
    }
    return p.join("");
};

!function(c, e, o, l, i, n) {
    c.definePlugin(i.GAMES_DROPDOWN, {
        init: function() {
            function onSharedFrameReady() {
                c.on("dropdownshow:sub-menu:games", function(dropdownElement) {
                    c.updateNewTabBubble(dropdownElement, c.configs.games.map(o.convertTrilogyNames));
                });
                pluginInstance.render();
            }

            var pluginInstance = this;

            c.on("render", this.render, this);

            c.on("dropdownshow:games", function(dropdownElement, targetTabName) {
                c.updateImagesSourceAttribute(dropdownElement);

                if (!c.TabCarousel) {
                    c.loadPlugin(i.TAB_CAROUSEL);
                }

                if (pluginInstance.TabCarousel) {
                    pluginInstance.TabCarousel.onDropdownOpen();
                    pluginInstance.openSpecificSubmenu(targetTabName);
                } else {
                    c.onPluginReady(i.TAB_CAROUSEL, function() {
                        pluginInstance.TabCarousel = new c.TabCarousel(dropdownElement, "games");
                        pluginInstance.openSpecificSubmenu(targetTabName);
                    });
                }
            });

            if (c.isSharedFrameReady()) {
                onSharedFrameReady();
            } else if (c.isSharedFrameFailed()) {
                this.render();
            } else {
                c.on("sharedFrame:ready", onSharedFrameReady, this);
                c.on("sharedFrame:fail", this.render, this);
            }
        },

        render: function() {
            var options = c.getOptions();
            var config = c.configs.games ? c.configs.games.map(o.convertTrilogyNames) : [];
            
            this.dropdownElement = e.findFirstByClass(n.jsGamesDropdownClass);

            if (this.dropdownElement) {
                var templateData = o.extend({}, l, {
                    options: options,
                    config: config
                });

                this.dropdownElement.innerHTML = c.gamesDropdownTemplate(templateData);
                c.activateDropdownLink(this.dropdownElement);
                c.updateLinksTargetAttribute(this.dropdownElement);
            }
        },

        openSpecificSubmenu: function(targetTabName) {
            targetTabName = c.openSubmenuOnDropdownShow(targetTabName);
            if (targetTabName && this.TabCarousel && this.TabCarousel.isInitialised) {
                this.TabCarousel.scrollTabIntoView(targetTabName);
            }
        }
    });
}(
    GS.CommonMenu,
    GS.CommonMenu.DOM,
    GS.CommonMenu.utils,
    GS.CommonMenu.templateHelpers,
    GS.CommonMenu.PLUGINS_NAMES,
    GS.CommonMenu.DEFAULT_CLASSES
);
